def load_golden_dataset() -> List[Dict[str, Any]]:
    """Load the golden QA dataset from disk or return the built-in set."""
    qa_path = settings.golden_qa_path
    if qa_path.exists():
        with open(qa_path, "r", encoding="utf-8") as f:
            return json.load(f)
    return GOLDEN_QA


def save_golden_dataset(path: Path | None = None) -> Path:
    """Save the built-in golden dataset to disk as JSON."""
    target = path or settings.golden_qa_path
    target.parent.mkdir(parents=True, exist_ok=True)
    with open(target, "w", encoding="utf-8") as f:
        json.dump(GOLDEN_QA, f, indent=2, ensure_ascii=False)
    return target


if __name__ == "__main__":
    saved = save_golden_dataset()
    print(f"Saved {len(GOLDEN_QA)} Q&A pairs to {saved}")
